#include <stdio.h>
#include <stddef.h>
#include <stdlib.h>

#define container_of(ptr, type, member) \
    ((type *)((char *)(ptr) - offsetof(type, member)))

typedef struct ListNode {
    struct ListNode *next;
} ListNode;

typedef struct {
    int pid;
    char name[16];
    ListNode link;
} Task;

void list_add(ListNode *head, ListNode *node) {
    node->next = head->next;
    head->next = node;
}

int main(void) {
    ListNode head = {NULL};

    Task t1 = {100, "init", {NULL}};
    Task t2 = {200, "bash", {NULL}};
    Task t3 = {300, "vim", {NULL}};

    list_add(&head, &t1.link);
    list_add(&head, &t2.link);
    list_add(&head, &t3.link);

    printf("Task list:\n");
    for (ListNode *n = head.next; n; n = n->next) {
        Task *t = container_of(n, Task, link);
        printf("  pid=%d name=%s\n", t->pid, t->name);
    }

    printf("offsetof(Task, link) = %zu\n", offsetof(Task, link));
    printf("sizeof(Task) = %zu\n", sizeof(Task));
    return 0;
}

